101	/**
102	 * 從主 session 檔案中提取所有 agentId
103	 */
104	export async function extractAgentIds(
105	  sessionPath: string
106	): Promise<Set<string>> {
107	  const agentIds = new Set<string>();
108	
109	  try {
110	    const file = Bun.file(sessionPath);
111	    const content = await file.text();
112	    const lines = content.split('\n').filter(Boolean);
113	
114	    for (const line of lines) {
115	      try {
116	        const data = JSON.parse(line);
117	        // 從 toolUseResult 中提取 agentId，並驗證格式以防止路徑穿越
118	        const agentId = data.toolUseResult?.agentId;
119	        if (agentId && isValidAgentId(agentId)) {
120	          agentIds.add(agentId);
121	        }
122	      } catch {
123	        // 忽略解析錯誤
124	      }
125	    }
126	  } catch {
127	    // 忽略檔案讀取錯誤
128	  }
129	
130	  return agentIds;
131	}
132	
133	/**
134	 * 掃描 subagents 目錄，找出尚未被監控的新 subagent 檔案
135	 * @param subagentsDir subagents 目錄路徑
136	 * @param knownAgentIds 已知的 agentId 集合
137	 * @returns 新發現的 agentId 陣列
138	 */
139	export async function scanForNewSubagents(
140	  subagentsDir: string,
141	  knownAgentIds: Set<string>
142	): Promise<string[]> {
143	  const newAgentIds: string[] = [];
144	
145	  try {
146	    const glob = new Glob('agent-*.jsonl');
147	    for await (const file of glob.scan({ cwd: subagentsDir })) {
148	      // Defensive: skip anything under a subdirectory (e.g. nested
149	      // workflows/wf_*/agent-*.jsonl). Bun.Glob is non-recursive by
150	      // default but this guard protects against future behavior changes.
151	      if (file.includes('/')) continue;
152	      // 從檔名 "agent-{id}.jsonl" 提取 id（支援 7-40 位 hex）
153	      const match = file.match(/^agent-([0-9a-f]{7,40})\.jsonl$/i);
154	      if (match && match[1]) {
155	        const agentId = match[1];
156	        if (!knownAgentIds.has(agentId)) {
157	          newAgentIds.push(agentId);
158	        }
159	      }
160	    }
161	  } catch {
162	    // 目錄不存在或無法存取時靜默忽略
163	    // 這是預期行為：subagent 可能尚未建立目錄
164	  }
165	
166	  return newAgentIds;
167	}
168	
169	// ============================================================
170	// Core Functions
171	// ============================================================
172	
173	/**
174	 * 嘗試新增 subagent 檔案監控（含重試邏輯）
175	 *
176	 * @param subagentPath - subagent 檔案路徑
177	 * @param agentId - agent 識別碼
178	 * @param watcher - watcher 處理器
179	 * @param output - 輸出處理器
180	 * @param config - 重試配置
181	 * @returns Promise<boolean> 是否成功新增
182	 */
183	export async function tryAddSubagentFile(
184	  subagentPath: string,
185	  agentId: string,
186	  watcher: WatcherHandler,
187	  output: OutputHandler,
188	  config: RetryConfig = FALLBACK_DETECTION_RETRY
189	): Promise<boolean> {
190	  const doTry = async (retriesLeft: number): Promise<boolean> => {
191	    try {
192	      const file = Bun.file(subagentPath);
193	      if (await file.exists()) {
194	        await watcher.addFile({
195	          path: subagentPath,
196	          label: makeAgentLabel(agentId),
197	        });
198	        return true;
199	      } else if (retriesLeft > 0) {
200	        await new Promise((resolve) => setTimeout(resolve, config.retryDelay));
201	        return doTry(retriesLeft - 1);
202	      } else {
203	        output.debug(`Subagent file not found after retries: ${agentId}`);
204	        return false;
205	      }
206	    } catch (error) {
207	      output.error(`Failed to add subagent watcher: ${agentId} - ${error}`);
208	      return false;
209	    }
210	  };
211	
212	  // 初始延遲後開始嘗試
213	  await new Promise((resolve) => setTimeout(resolve, config.initialDelay));
214	  return doTry(config.maxRetries);
215	}
216	
217	// ============================================================
218	// SubagentDetector Class
219	// ============================================================
220	
221	/**
222	 * Subagent 偵測器 - 整合 early detection 和 fallback detection
223	 */
224	export class SubagentDetector {
225	  private knownAgentIds: Set<string>;
226	  private config: SubagentDetectorConfig;
227	  private dirWatcher: FSWatcher | null = null;
228	  private parentWatcher: FSWatcher | null = null;
229	  private scanTimer: ReturnType<typeof setTimeout> | null = null;
230	  private isWatching = false;
231	  // 追蹤所有 pending 的 setTimeout 句柄，用於 stop() 時清除
232	  private pendingTimers: Set<ReturnType<typeof setTimeout>> = new Set();
233	  // FIFO queue: Task tool_use descriptions, matched to agents in registration order.
234	  // May mismatch with parallel Task launches (known limitation, wrong label only).
235	  private pendingDescriptions: string[] = [];
236	
237	  constructor(initialAgentIds: Set<string>, config: SubagentDetectorConfig) {
238	    this.knownAgentIds = new Set(initialAgentIds);
239	    this.config = config;
240	  }
241	
242	  /**
243	   * 啟動 subagents 目錄監控（自動偵測新檔案）
244	   */
245	  startDirectoryWatch(): void {
246	    if (!this.config.enabled) return;
247	    if (this.isWatching) return;
248	    if (this.config.watchDir === false) return;
249	
250	    this.isWatching = true;
251	    this.tryWatchSubagentsDir();
252	  }
253	
254	  /**
255	   * 停止所有監控
256	   */
257	  stop(): void {
258	    this.isWatching = false;
259	    this.clearScanTimer();
260	    // 清除所有 pending 的 setTimeout
261	    for (const timer of this.pendingTimers) {
262	      clearTimeout(timer);
263	    }
264	    this.pendingTimers.clear();
265	    this.pendingDescriptions = [];
266	    this.dirWatcher?.close();
267	    this.dirWatcher = null;
268	    this.parentWatcher?.close();
269	    this.parentWatcher = null;
