            options.verbose
          );
          const label = makeAgentLabel(agentId);
          for (const part of parts) {
            part.sourceLabel = label;
            console.log(formatter.format(part));
          }
        } catch {
          // 讀取失敗不影響 pane 關閉
        } finally {
          await pm.closePaneByAgentId(agentId);
        }
      })().catch(() => {});
    }
  : undefined;

const hasPaneCallback = pm
  ? (agentId: string) => pm.hasPaneForAgent(agentId)
  : undefined;

// pane 模式下，進入時既有 subagent 加入 suppress set，避免歷史內容污染 main pane
const suppressedForPane = pm ? new Set(existingAgentIds) : new Set<string>();

const shouldOutput = pm
  ? (label: string) => {
      if (label === MAIN_LABEL) return true;
      const agentId = extractAgentIdFromLabel(label);
      if (suppressedForPane.has(agentId)) return false;
      return !pm.hasPaneForAgent(agentId);
    }
  : undefined;

// 建立 SubagentDetector（整合 early detection 和 fallback detection）
let detector = new SubagentDetector(existingAgentIds, {
  subagentsDir,
  output: new ConsoleOutputHandler(),
  watcher: { addFile: (f) => multiWatcher.addFile(f) },
  session: new NoOpSessionHandler(),
  enabled: options.follow && options.withSubagents,
  onNewSubagent: openPaneForSubagent,
  onSubagentEnter: openPaneForSubagent,
  onSubagentDone,
  hasPane: hasPaneCallback,
});
detector.startDirectoryWatch();

// P5 — Workflow auto-attach (default on; --no-workflow-attach disables)
const wfAttachments = new Map<string, WorkflowAttachment>();
let workflowDetector: WorkflowDetector | undefined;
if (options.workflowAttach !== false) {
  const wfOutputHandler = new ConsoleOutputHandler();
  workflowDetector = new WorkflowDetector({
    sessionUuid: basename(sessionFile.path, '.jsonl'),
    sessionDir: dirname(sessionFile.path),
    outputHandler: wfOutputHandler,
    onNewWorkflow: async (workflow) => {
      if (wfAttachments.has(workflow.runId)) return;
      const attachment = new WorkflowAttachment({
        workflow,
        withAgents: options.withWorkflowAgents !== false,
        verbose: options.verbose,
        follow: options.follow,
        pollInterval: options.sleepInterval,
        initialLines: options.lines,
        formatter,
        onOutput: (formatted) => process.stdout.write(`${formatted}\n`),
        outputHandler: wfOutputHandler,
        onStop: () => {
          wfAttachments.delete(workflow.runId);
        },
      });
      wfAttachments.set(workflow.runId, attachment);
      try {
        await attachment.start();
      } catch (err) {
        wfOutputHandler.debug(
          `[wf:${workflow.runId}] attachment start failed: ${err}`
        );
        wfAttachments.delete(workflow.runId);
        throw err;
      }
    },
  });
  await workflowDetector.start();
}

// ========== Non-Interactive Super-Follow ==========
let currentSessionPath = sessionFile.path;

const switchToSession = async (
  nextSessionFile: SessionFile
): Promise<void> => {
  // 停止現有監控
  detector?.stop();
  // P5 — super-follow swap: the old detector is bound to the old
  // sessionDir; stop it AND clear out any in-flight workflow
  // attachments before binding a new detector for the new session.
  workflowDetector?.stop();
  workflowDetector = undefined;
  for (const att of wfAttachments.values()) {
    void att.stop('user');
  }
  wfAttachments.clear();
  multiWatcher.stop();

  // 更新當前 session 路徑
  currentSessionPath = nextSessionFile.path;

  // 重新初始化監控
  const newSessionId = basename(nextSessionFile.path, '.jsonl');

