  if (idx >= 0) this.insertionOrder.splice(idx, 1);
  this.pinnedAgentIds.delete(agentId);

  try {
    await this.controller.closePane(pane.id);
  } catch {
    // 靜默忽略關閉失敗（pane 可能已經關閉）
  }
}

