  const tmpDir = await mkdtemp(join(tmpdir(), 'subagent-parent-'));
  const subagentsDir = join(tmpDir, 'subagents');
  await mkdir(subagentsDir, { recursive: true });

  // Nested subagent (level-2): spawned by parent agent ace4e3f
