117	/**
118	 * 建立標準 onLine handler，供 MultiFileWatcher 的 onLine callback 使用
119	 */
120	export function createOnLineHandler(
121	  config: OnLineHandlerConfig
122	): (line: string, label: string) => void {
123	  return (line: string, label: string) => {
124	    // agent_progress：subagent 進入或 resume，每次進入都觸發 pane 開啟
125	    // 前置字串檢查避免每行都 JSON.parse（熱路徑優化）
126	    if (label === MAIN_LABEL && line.includes('"agent_progress"')) {
127	      try {
128	        const data = JSON.parse(line) as {
129	          type?: string;
130	          data?: { type?: string; agentId?: string };
131	        };
132	        if (
133	          data.type === 'progress' &&
134	          data.data?.type === 'agent_progress' &&
135	          data.data?.agentId
136	        ) {
137	          config.detector.handleAgentProgress(data.data.agentId);
138	        }
139	      } catch {
140	        // 非 JSON 或無關格式，略過
141	      }
142	    }
143	
144	    let parser = config.parsers.get(label);
145	    if (!parser) {
146	      const newAgent = new ClaudeAgent({ verbose: config.verbose });
147	      parser = newAgent.parser;
148	      config.parsers.set(label, parser);
149	    }
150	
151	    let parsed = parser.parse(line);
152	    while (parsed) {
153	      parsed.sourceLabel = label;
154	
155	      // Phase 2.3: 過濾已有 pane 的 subagent 輸出
156	      if (config.shouldOutput && !config.shouldOutput(label)) {
157	        parsed = parser.parse(line);
158	        continue;
159	      }
160	
161	      config.onOutput(config.formatter.format(parsed), label);
162	
163	      // Real-time custom-title update
164	      if (
165	        label === MAIN_LABEL &&
166	        parsed.isCustomTitle &&
167	        parsed.customTitleValue
168	      ) {
169	        config.onTitleUpdate?.(parsed.customTitleValue);
170	      }
171	
172	      // 早期 Subagent 偵測：當偵測到 Task tool_use 時立即掃描
173	      // 只有主 session 走完整偵測流程（FIFO push + early detection scan）
174	      // nested 那層的 description 改靠 meta.json 補；dir watch 處理檔案出現
175	      if (parsed.isTaskToolUse && label === MAIN_LABEL) {
176	        if (parsed.taskDescription) {
177	          config.detector.pushDescription(parsed.taskDescription);
178	        }
179	        config.detector.handleEarlyDetection();
180	      }
181	      // Phase 2: 紀錄 spawn 關係（主 session 與 nested 都收）
182	      // nested subagent 註冊時靠此 map 反查 parent → 組 [child◂parent] label
183	      if (parsed.isTaskToolUse && parsed.taskToolUseId) {
184	        const parentLabel =
185	          label === MAIN_LABEL ? MAIN_SOURCE : extractAgentIdFromLabel(label);
186	        config.detector.recordSpawn(parsed.taskToolUseId, parentLabel);
187	      }
